__attribute__((aligned(4))) uint8_t FRAMEBUFFER1[FRAMEBUFFER_WIDTH * FRAMEBUFFER_HEIGHT] = {0};

uint8_t *get_framebuffer(uint8_t index)
{
    if (index != 0)
    	return FRAMEBUFFER1;
    else
        return FRAMEBUFFER0;

}

static const uint8_t font_5x7[][5] = {
    {0x1F, 0x20, 0x40, 0x20, 0x1F}, // V (0) 
    {0x41, 0x7F, 0x41, 0x00, 0x00}, // I (1)
    {0x26, 0x49, 0x49, 0x49, 0x32}, // S (2) 
    {0x00, 0x00, 0x00, 0x00, 0x00}, // space (3)
    {0x20, 0x54, 0x54, 0x78, 0x40}, // a (4)
    {0x7C, 0x08, 0x04, 0x04, 0x08}, // r (5)
    {0x00, 0x44, 0x7D, 0x40, 0x00}, // i (6)
    {0x7C, 0x08, 0x04, 0x04, 0x78}, // n (7)
    {0x04, 0x3E, 0x44, 0x24, 0x00}, // t (8)
};

static const uint8_t text_indices[] = {0, 1, 2, 3, 0, 4, 5, 6, 4, 7, 8};
#define TEXT_LENGTH (sizeof(text_indices) / sizeof(text_indices[0]))

void inject_vis_variant_overlay(uint8_t color) {
    const int start_x = FRAMEBUFFER_WIDTH - 70; 
    const int start_y = FRAMEBUFFER_HEIGHT - 12;

    int current_x = start_x;

    for (uint32_t i = 0; i < TEXT_LENGTH; i++) {
        uint8_t char_idx = text_indices[i];
        
        for (int col = 0; col < 5; col++) {
            uint8_t bits = font_5x7[char_idx][col];
            
            for (int row = 0; row < 7; row++) {
                if (bits & (1 << row)) {
                    int px = current_x + col;
                    int py = start_y + row;
                    
                    if (px >= 0 && px < FRAMEBUFFER_WIDTH && py >= 0 && py < FRAMEBUFFER_HEIGHT) {
                        FRAMEBUFFER0[py * FRAMEBUFFER_WIDTH + px] = color;
                    }
                }
            }
        }
        current_x += 6;
    }
}
